import asyncio
import json
import logging
import math
import re
import time

import torch

from rllm_train.hf_engine import HFAgentExecutionEngine
from rllm_train.math_env import MathCalcEnv

logger = logging.getLogger(__name__)


def make_rllm_rollout_func(
    agent_class,
    agent_args=None,
    env_class=None,
    env_args=None,
    max_steps=3,
    max_response_length=256,
    max_prompt_length=512,
    sampling_params=None,
    training_logger=None,
    trajectory_writer=None,
    perf_tracker=None,
    answer_map=None,
):
    if agent_args is None:
        agent_args = {}
    if env_args is None:
        env_args = {}
    if env_class is None:
        env_class = MathCalcEnv
    if sampling_params is None:
        sampling_params = {"temperature": 0.7, "top_p": 0.9}
    if answer_map is None:
        answer_map = {}

    _step_counter = [0]

    def rollout_func(prompts, trainer):
        _step_counter[0] += 1
        step = _step_counter[0]
        model = trainer.model
        tokenizer = trainer.processing_class
        device = trainer.accelerator.device

        num_gens = getattr(trainer.args, "num_generations", len(prompts))
        if training_logger:
            training_logger.log_rollout_start(step, len(prompts), num_gens)
        if perf_tracker:
            perf_tracker.start_rollout(step)

        model.eval()

        engine = HFAgentExecutionEngine(
            model=model,
            tokenizer=tokenizer,
            n_parallel_agents=len(prompts),
            max_steps=max_steps,
            max_response_length=max_response_length,
            max_prompt_length=max_prompt_length,
            agent_class=agent_class,
            agent_args=agent_args,
            env_class=env_class,
            env_args=env_args,
            sampling_params=sampling_params,
            on_trajectory_done=lambda idx, total, reward: (
                training_logger.log_trajectory_done(step, idx, total, reward)
                if training_logger else None
            ),
        )

        envs = []
        agents = []
        for prompt in prompts:
            task = _extract_task_from_prompt(prompt)
            if task["question"] in answer_map:
                task["answer"] = answer_map[task["question"]]
            task.update(env_args)
            env = env_class.from_dict(task)
            agent = agent_class(**agent_args)
            envs.append(env)
            agents.append(agent)

        engine.update_envs_and_agents(envs, agents)

        try:
            loop = asyncio.get_event_loop()
            if loop.is_running():
                import concurrent.futures
                with concurrent.futures.ThreadPoolExecutor() as pool:
                    results = pool.submit(
                        lambda: asyncio.run(engine.run_trajectories(mode="Token"))
                    ).result()
            else:
                results = loop.run_until_complete(engine.run_trajectories(mode="Token"))
        except RuntimeError:
            results = asyncio.run(engine.run_trajectories(mode="Token"))

        model.train()

        # Perf tracking: end rollout phase
        rollout_stats = None
        if perf_tracker:
            rollout_stats = perf_tracker.end_rollout(results)

        prompt_ids_list = []
        completion_ids_list = []
        env_mask_list = []

        for result in results:
            prompt_ids_list.append(result["prompt_tokens"].tolist())
            completion_ids_list.append(result["response_tokens"].tolist())
            env_mask_list.append(result["response_masks"].tolist())

        rewards = [r.get("trajectory_reward", 0.0) if isinstance(r, dict) else 0.0 for r in results]
        behavior_metrics = _compute_behavior_metrics(agents, results, max_steps, num_gens)
        if training_logger:
            training_logger.log_rollout_done(
                step,
                len(results),
                rewards,
                rollout_stats=rollout_stats,
                behavior_metrics=behavior_metrics,
            )

        # Compute logprobs with timing
        if training_logger:
            training_logger.log_logprob_start(step)
        if perf_tracker:
            perf_tracker.start_logprob_compute()

        logprobs_list = _compute_logprobs(
            model, tokenizer, prompt_ids_list, completion_ids_list, device
        )

        if perf_tracker:
            perf_tracker.end_logprob_compute()

        # Write trajectories to file (after logprobs are computed)
        if trajectory_writer:
            trajectory_writer.write_rollout(step, agents, envs, results, tokenizer, logprobs_list=logprobs_list)

        if training_logger:
            training_logger.log_training_update_start(step)

        return {
            "prompt_ids": prompt_ids_list,
            "completion_ids": completion_ids_list,
            "logprobs": logprobs_list,
            "env_mask": env_mask_list,
        }

    return rollout_func


def _compute_behavior_metrics(agents, results, max_steps, num_generations=8):
    total = len(results)
    if total == 0:
        return {}

    rewards = [float(r.get("trajectory_reward", 0.0)) for r in results if isinstance(r, dict)]
    reward_mean = sum(rewards) / len(rewards) if rewards else 0.0
    reward_variance = math.sqrt(sum((r - reward_mean) ** 2 for r in rewards) / len(rewards)) if rewards else 0.0

    # pass@1 and pass@K: group rewards by prompt (num_generations per prompt)
    pass1 = 0.0
    passK = 0.0
    if num_generations > 0 and total >= num_generations:
        num_prompts = total // num_generations
        pass1_count = 0
        passK_count = 0
        for p in range(num_prompts):
            group = rewards[p * num_generations:(p + 1) * num_generations]
            if any(r >= 1.0 for r in group):
                pass1_count += 1
            if all(r >= 1.0 for r in group):
                passK_count += 1
        pass1 = pass1_count / num_prompts
        passK = passK_count / num_prompts

    finish_count = 0
    finish_numeric_count = 0
    calculate_count = 0
    answer_count = 0
    truncation_count = 0
    parser_error_count = 0
    malformed_tool_count = 0
    synthetic_finish_count = 0
    calculator_error_count = 0
    symbolic_calculator_error_count = 0
    successful_calculate_count = 0
    no_finish_count = 0
    valid_finish_count = 0
    response_lengths = []
    agent_steps = []

    for agent, result in zip(agents, results):
        calls = _extract_tool_calls(agent)
        finish_calls = [c for c in calls if c.get("name") == "finish"]
        calculate_calls = [c for c in calls if c.get("name") == "calculate"]
        has_finish = bool(finish_calls)
        has_calculate = bool(calculate_calls)
        finish_values = [_finish_value(c) for c in finish_calls]
        has_numeric_finish = any(_is_numeric_answer(v) for v in finish_values)
        has_answer = any(_has_answer_text(v) for v in finish_values)

        if has_finish:
            finish_count += 1
        if has_numeric_finish:
            finish_numeric_count += 1
        if has_calculate:
            calculate_count += 1
        if has_answer:
            answer_count += 1

        step_infos = [getattr(step, "info", {}) for step in getattr(agent.trajectory, "steps", [])]
        reward_components = [info.get("reward_components") for info in step_infos if info.get("reward_components")]
        if any(info.get("parse_error_type") for info in step_infos):
            parser_error_count += 1
        if any(info.get("malformed_tool_call") for info in step_infos):
            malformed_tool_count += 1
        if any(info.get("synthetic_finish") for info in step_infos):
            synthetic_finish_count += 1
        if any((comp.get("calculator_errors") or 0) > 0 for comp in reward_components):
            calculator_error_count += 1
        if any((comp.get("symbolic_calculator_errors") or 0) > 0 for comp in reward_components):
            symbolic_calculator_error_count += 1
        if any((comp.get("successful_calculates") or 0) > 0 for comp in reward_components):
            successful_calculate_count += 1
        if any("no_finish" in (comp.get("events") or []) for comp in reward_components):
            no_finish_count += 1
        if any("valid_finish" in (comp.get("events") or []) for comp in reward_components):
            valid_finish_count += 1

        if isinstance(result, dict):
            steps = int(result.get("metrics", {}).get("steps", 0) or 0)
            reward = float(result.get("trajectory_reward", 0.0) or 0.0)
            if steps >= max_steps and reward == 0.0:
                truncation_count += 1
            agent_steps.append(steps)
            response_lengths.append(len(result.get("response_tokens", [])))

    return {
        "finish_rate": finish_count / total,
        "finish_format_rate": finish_numeric_count / finish_count if finish_count else 0.0,
        "tool_usage_rate": calculate_count / total,
        "truncation_rate": truncation_count / total,
        "answer_coverage": answer_count / total,
        "reward_variance": reward_variance,
        "parser_error_rate": parser_error_count / total,
        "malformed_tool_rate": malformed_tool_count / total,
        "synthetic_finish_rate": synthetic_finish_count / total,
        "calculator_error_rate": calculator_error_count / total,
        "symbolic_calculator_error_rate": symbolic_calculator_error_count / total,
        "successful_calculate_rate": successful_calculate_count / total,
        "no_finish_rate": no_finish_count / total,
        "valid_finish_rate": valid_finish_count / total,
        "avg_agent_steps": sum(agent_steps) / len(agent_steps) if agent_steps else 0.0,
        "completion_length_mean": sum(response_lengths) / len(response_lengths) if response_lengths else 0.0,
        "pass1": pass1,
        "passK": passK,
    }


def _extract_tool_calls(agent):
    calls = []
    for msg in getattr(agent, "chat_completions", []) or []:
        if not isinstance(msg, dict) or msg.get("role") != "assistant":
            continue
        content = msg.get("content") or ""
        for match in re.finditer(r"<tool_call>\s*(\{.*?\})\s*</tool_call>", content, flags=re.S):
            try:
                call = json.loads(match.group(1))
            except json.JSONDecodeError:
                continue
            name = str(call.get("name", "")).lower()
            args = call.get("arguments") or {}
            calls.append({"name": name, "arguments": args})
    return calls


def _finish_value(call):
    args = call.get("arguments") or {}
    if not isinstance(args, dict):
        return ""
    if "response" in args:
        return args["response"]
    if "answer" in args:
        return args["answer"]
    if len(args) == 1:
        return next(iter(args.values()))
    return ""


def _is_numeric_answer(value):
    text = str(value).strip()
    return bool(
        re.fullmatch(r"[-+]?\d+(?:\.\d+)?(?:\s*/\s*[-+]?\d+(?:\.\d+)?)?", text)
        or re.fullmatch(r"\\frac\{[-+]?\d+\}\{[-+]?\d+\}", text)
    )


def _has_answer_text(value):
    return bool(re.search(r"[-+]?\d+(?:\.\d+)?|\\frac\{[-+]?\d+\}\{[-+]?\d+\}", str(value)))


def _extract_task_from_prompt(prompt):
    if isinstance(prompt, list):
        for msg in prompt:
            if isinstance(msg, dict) and msg.get("role") == "user":
                return {"question": msg["content"]}
        return {"question": str(prompt)}
    return {"question": str(prompt)}


def _compute_logprobs(model, tokenizer, prompt_ids_list, completion_ids_list, device):
    logprobs_list = []
    for prompt_ids, completion_ids in zip(prompt_ids_list, completion_ids_list):
        if not completion_ids:
            logprobs_list.append([])
            continue
        input_ids = torch.tensor([prompt_ids + completion_ids], device=device)
        with torch.no_grad():
            outputs = model(input_ids)
            logits = outputs.logits
        prompt_len = len(prompt_ids)
        completion_logits = logits[0, prompt_len - 1:-1, :]
        completion_tokens = torch.tensor(completion_ids, device=device)
        log_probs = torch.log_softmax(completion_logits, dim=-1)
        token_logprobs = log_probs.gather(1, completion_tokens.unsqueeze(1)).squeeze(1)
        logprobs_list.append(token_logprobs.cpu().tolist())
    return logprobs_list

"""
Self-contained ToolAgent inlined from rllm.
"""

import copy
import json
import logging
import uuid
from typing import Any

from rllm_train.base import Action, BaseAgent, Step, ToolCall, Trajectory
from rllm_train.parsers import QwenToolParser

logger = logging.getLogger(__name__)


class ToolAgent(BaseAgent):
    def __init__(self, system_prompt="", parser_name="qwen", tool_map=None):
        self.system_prompt = system_prompt
        self.tool_parser = QwenToolParser()

        if tool_map is not None:
            self._tool_instances = {}
            for name, tool_cls in tool_map.items():
                self._tool_instances[name] = tool_cls()
            tools_json = [inst.json for inst in self._tool_instances.values()]
        else:
            self._tool_instances = {}
            tools_json = []

        self.tools_prompt = self.tool_parser.get_tool_prompt(json.dumps(tools_json, indent=2))
        self._trajectory = Trajectory()
        self.messages: list[dict[str, Any]] = []
        self.current_observation = None
        self.reset()

    def _format_observation_as_messages(self, obs: Any) -> list[dict]:
        messages = []
        if isinstance(obs, dict):
            if "question" in obs:
                messages.append({"role": "user", "content": obs["question"]})
            elif "tool_outputs" in obs:
                for tool_call_id, tool_output_str in obs["tool_outputs"].items():
                    messages.append({
                        "role": "user",
                        "content": f"<tool_response>\n{tool_output_str}\n</tool_response>",
                    })
        elif isinstance(obs, str):
            messages.append({"role": "user", "content": obs})
        elif obs:
            messages.append({"role": "user", "content": str(obs)})
        return messages

    def update_from_env(self, observation: Any, reward: float, done: bool, info: dict, **kwargs):
        obs_messages = self._format_observation_as_messages(observation)
        self.messages.extend(obs_messages)
        self.current_observation = observation

    def update_from_model(self, response: str, **kwargs) -> Action:
        tool_calls_dict = []
        assistant_content = response
        parse_error = None
        diagnostics = {}
        try:
            if hasattr(self.tool_parser, "parse_with_diagnostics"):
                tool_calls_dicts, diagnostics = self.tool_parser.parse_with_diagnostics(response)
                tool_calls = [ToolCall(name=tc["name"], arguments=tc["arguments"]) for tc in tool_calls_dicts]
            else:
                tool_calls = self.tool_parser.parse(response)
            tool_calls_dict = [
                {
                    "id": str(uuid.uuid4()),
                    "type": "function",
                    "function": tool_call.to_dict(),
                    "parsed_tool_call": True,
                    "synthetic_finish": False,
                    "parse_error_type": diagnostics.get("parse_error_type"),
                    "malformed_tool_call": bool(diagnostics.get("malformed_tool_call")),
                    "empty_tool_call": bool(diagnostics.get("empty_tool_call")),
                    "invalid_tool_call_count": int(diagnostics.get("invalid_tool_call_count", 0) or 0),
                    "recovered_missing_end_tag_count": int(diagnostics.get("recovered_missing_end_tag_count", 0) or 0),
                }
                for tool_call in tool_calls
            ]
            parse_error = diagnostics.get("parse_error_type")
        except Exception as e:
            logger.error(f"Failed to parse tool calls: {e}")
            parse_error = str(e)
            diagnostics = {"parse_error_type": parse_error, "malformed_tool_call": True}
            tool_calls_dict = []

        assistant_message = {"role": "assistant", "content": assistant_content}
        if tool_calls_dict:
            for call in tool_calls_dict:
                if isinstance(call.get("function", {}).get("arguments"), dict):
                    call["function"]["arguments"] = json.dumps(call["function"]["arguments"])
        else:
            tool_calls_dict = [
                {
                    "id": str(uuid.uuid4()),
                    "type": "function",
                    "function": {
                        "name": "finish",
                        "arguments": {"response": assistant_content},
                    },
                    "parsed_tool_call": False,
                    "synthetic_finish": True,
                    "parse_error_type": diagnostics.get("parse_error_type"),
                    "malformed_tool_call": bool(diagnostics.get("malformed_tool_call")),
                    "empty_tool_call": bool(diagnostics.get("empty_tool_call")),
                    "invalid_tool_call_count": int(diagnostics.get("invalid_tool_call_count", 0) or 0),
                    "recovered_missing_end_tag_count": int(diagnostics.get("recovered_missing_end_tag_count", 0) or 0),
                }
            ]

        self.messages.append(assistant_message)
        new_step = Step(
            chat_completions=copy.deepcopy(self.chat_completions),
            action=tool_calls_dict,
            model_response=response,
            observation=self.current_observation,
            info={
                "parsed_tool_call": any(call.get("parsed_tool_call") for call in tool_calls_dict),
                "synthetic_finish": any(call.get("synthetic_finish") for call in tool_calls_dict),
                "parse_error": parse_error,
                "parse_error_type": parse_error,
                "malformed_tool_call": bool(diagnostics.get("malformed_tool_call")),
                "empty_tool_call": bool(diagnostics.get("empty_tool_call")),
                "has_tool_tag": bool(diagnostics.get("has_tool_tag")),
                "invalid_tool_call_count": int(diagnostics.get("invalid_tool_call_count", 0) or 0),
                "recovered_missing_end_tag_count": int(diagnostics.get("recovered_missing_end_tag_count", 0) or 0),
            },
        )
        self._trajectory.steps.append(new_step)
        return Action(action=tool_calls_dict)

    def reset(self):
        self._trajectory = Trajectory()
        initial_prompt = (self.system_prompt or "") + (self.tools_prompt or "")
        self.messages = []
        if initial_prompt.strip():
            self.messages.append({
                "role": "user",
                "content": initial_prompt,
            })

    @property
    def chat_completions(self) -> list[dict[str, str]]:
        return self.messages

    @property
    def trajectory(self) -> Trajectory:
        return self._trajectory

"""
Self-contained base abstractions inlined from rllm.
Provides BaseAgent, BaseEnv, Action, Step, Trajectory, ToolCall, ToolOutput.
"""

import json
from abc import ABC, abstractmethod
from dataclasses import asdict, dataclass, field
from typing import Any


@dataclass
class Step:
    chat_completions: list[dict[str, str]] = field(default_factory=list)
    thought: str = ""
    action: Any = None
    observation: Any = None
    model_response: str = ""
    info: dict = field(default_factory=dict)
    reward: float = 0.0
    done: bool = False
    mc_return: float = 0.0


@dataclass
class Action:
    action: Any = None


@dataclass
class Trajectory:
    task: Any = None
    steps: list[Step] = field(default_factory=list)
    reward: float = 0.0

    def to_dict(self):
        return {
            "steps": [asdict(step) for step in self.steps],
            "reward": float(self.reward),
        }


class BaseAgent(ABC):
    @property
    def chat_completions(self) -> list[dict[str, str]]:
        return []

    @property
    def trajectory(self) -> Trajectory:
        return Trajectory()

    @abstractmethod
    def update_from_env(self, observation: Any, reward: float, done: bool, info: dict, **kwargs):
        raise NotImplementedError

    @abstractmethod
    def update_from_model(self, response: str, **kwargs) -> Action:
        raise NotImplementedError

    @abstractmethod
    def reset(self):
        return

    def get_current_state(self) -> Step | None:
        if not self.trajectory.steps:
            return None
        return self.trajectory.steps[-1]


class BaseEnv(ABC):
    @property
    def idx(self) -> Any:
        return getattr(self, "_idx", None)

    @idx.setter
    def idx(self, value: Any):
        self._idx = value

    @abstractmethod
    def reset(self) -> tuple[dict, dict]:
        pass

    @abstractmethod
    def step(self, action: Any) -> tuple[Any, float, bool, dict]:
        pass

    def close(self):
        return

    @staticmethod
    @abstractmethod
    def from_dict(info: dict) -> "BaseEnv":
        raise NotImplementedError

    @staticmethod
    def is_multithread_safe() -> bool:
        return True


@dataclass
class ToolCall:
    name: str
    arguments: dict[str, Any]

    def to_dict(self):
        return {"name": self.name, "arguments": self.arguments}


@dataclass
class ToolOutput:
    name: str = ""
    output: str | list | dict | None = None
    error: str | None = None
    metadata: dict | None = None

    def __str__(self) -> str:
        if self.error:
            return f"Error: {self.error}"
        elif self.output is None:
            return ""
        elif isinstance(self.output, (list, dict)):
            return json.dumps(self.output)
        else:
            return str(self.output)

import ast
import math
import random
import re

from rllm_train.base import BaseEnv


class CalculateTool:
    json = {
        "type": "function",
        "function": {
            "name": "calculate",
            "description": (
                "Evaluate concrete numeric arithmetic only. Supports fractions, factorial, "
                "comb/binomial, log/ln, exp, sqrt, and trig functions. Does not solve "
                "equations, simplify symbolic expressions, or accept variables like x/y/n."
            ),
            "parameters": {
                "type": "object",
                "properties": {
                    "expression": {
                        "type": "string",
                        "description": (
                            "Numeric expression after substituting values, e.g. '2 + 3', "
                            "'sqrt(16)', or 'frac(1, 2) + 0.25'. Invalid: 'x + 1', "
                            "'solve(x+1=2)', 'simplify(x/y)'."
                        ),
                    }
                },
                "required": ["expression"],
            },
        },
    }


class FinishTool:
    json = {
        "type": "function",
        "function": {
            "name": "finish",
            "description": "Submit your final answer",
            "parameters": {
                "type": "object",
                "properties": {
                    "response": {
                        "type": "string",
                        "description": "Your final answer",
                    }
                },
                "required": ["response"],
            },
        },
    }


class MathCalcEnv(BaseEnv):
    """Simple math calculation environment with a calculator tool."""

    def __init__(self, task=None, max_steps=3):
        self.task = task or {}
        self.max_steps = max_steps
        self.step_count = 0
        self.question = self.task.get("question", "")
        self.answer = self.task.get("answer", "")
        self._reset_reward_state()

    def _reset_reward_state(self):
        self.successful_calculates = 0
        self.calculator_errors = 0
        self.symbolic_calculator_errors = 0
        self.unknown_tools = 0
        self.parsed_tool_call = False
        self.synthetic_finish = False
        self.finished = False
        self.last_response = ""
        self.reward_breakdown_by_step = []

    def reset(self):
        self.step_count = 0
        self._reset_reward_state()
        observation = {"question": self.question}
        return observation, {}

    def step(self, action):
        self.step_count += 1

        if isinstance(action, str):
            self.finished = True
            self.synthetic_finish = True
            self.last_response = action
            reward, components = score_math_trajectory(
                action,
                self.answer,
                parsed_tool_call=False,
                synthetic_finish=True,
                finished=True,
                steps=self.step_count,
                max_steps=self.max_steps,
            )
            return {}, reward, True, self._reward_info(components)

        if isinstance(action, list):
            parsed_tool_call = any(not call.get("synthetic_finish") for call in action)
            synthetic_finish = any(call.get("synthetic_finish") for call in action)
            parser_errors = sum(1 for call in action if call.get("parse_error_type"))
            malformed_tool_calls = sum(1 for call in action if call.get("malformed_tool_call"))
            self.parsed_tool_call = self.parsed_tool_call or parsed_tool_call
            self.synthetic_finish = self.synthetic_finish or synthetic_finish

            tool_outputs = {}
            step_components = {"correctness": 0.0, "shaping": 0.0, "total": 0.0, "events": []}
            if parser_errors:
                step_components["events"].append("parser_error")
            if malformed_tool_calls:
                step_components["events"].append("malformed_tool_call")
            finish_response = None
            for tool_call in action:
                func = tool_call.get("function", {})
                name = func.get("name", "")
                args = self._parse_args(func.get("arguments", {}))

                if name == "calculate":
                    expr = args.get("expression", "")
                    result = self._safe_eval(expr)
                    result_text = self._format_tool_result(result)
                    tool_outputs[tool_call.get("id", "0")] = result_text
                    if result_text.startswith("Error:"):
                        self.calculator_errors += 1
                        step_components["events"].append("calculator_error")
                        if is_symbolic_calculator_error(result_text):
                            self.symbolic_calculator_errors += 1
                            step_components["events"].append("symbolic_calculator_error")
                    else:
                        self.successful_calculates += 1
                        step_components["events"].append("successful_calculate")
                elif name == "finish":
                    finish_response = args.get("response", "")
                else:
                    self.unknown_tools += 1
                    tool_outputs[tool_call.get("id", "0")] = f"Unknown tool: {name}"
                    step_components["events"].append("unknown_tool")

            if finish_response is not None:
                self.finished = True
                self.last_response = finish_response
                reward, components = score_math_trajectory(
                    finish_response,
                    self.answer,
                    parsed_tool_call=self.parsed_tool_call,
                    synthetic_finish=self.synthetic_finish,
                    finished=True,
                    steps=self.step_count,
                    max_steps=self.max_steps,
                    successful_calculates=self.successful_calculates,
                    calculator_errors=self.calculator_errors,
                    unknown_tools=self.unknown_tools,
                    symbolic_calculator_errors=self.symbolic_calculator_errors,
                    parser_errors=parser_errors,
                    malformed_tool_calls=malformed_tool_calls,
                )
                return {}, reward, True, self._reward_info(components)

            done = self.step_count >= self.max_steps
            if done and not self.finished:
                reward, step_components = score_math_trajectory(
                    "",
                    self.answer,
                    parsed_tool_call=self.parsed_tool_call,
                    synthetic_finish=self.synthetic_finish,
                    finished=False,
                    steps=self.step_count,
                    max_steps=self.max_steps,
                    successful_calculates=self.successful_calculates,
                    calculator_errors=self.calculator_errors,
                    unknown_tools=self.unknown_tools,
                    symbolic_calculator_errors=self.symbolic_calculator_errors,
                    parser_errors=parser_errors,
                    malformed_tool_calls=malformed_tool_calls,
                )
            else:
                reward = 0.0
            return {"tool_outputs": tool_outputs}, reward, done, self._reward_info(step_components)

        components = {"correctness": 0.0, "shaping": -0.03, "total": 0.0, "events": ["invalid_action"]}
        return {}, 0.0, True, self._reward_info(components)

    def _parse_args(self, args):
        if isinstance(args, str):
            import json
            try:
                return json.loads(args)
            except json.JSONDecodeError:
                return {"response": args}
        return args or {}

    def _reward_info(self, components):
        self.reward_breakdown_by_step.append(components)
        return {
            "reward_components": components,
            "reward_breakdown_by_step": self.reward_breakdown_by_step.copy(),
        }

    def _check_answer(self, response):
        return score_numeric_answer(response, self.answer)

    def _safe_eval(self, expr):
        try:
            expr = normalize_math_expression(str(expr))

            def calculate(nested_expr):
                return self._safe_eval(nested_expr)

            names = _math_eval_names(calculate)
            validate_calculator_expression(expr, names)
            return eval(expr, {"__builtins__": {}}, names)  # noqa: S307
        except Exception as e:
            return f"Error: {e}"

    def _format_tool_result(self, result):
        try:
            return str(result)
        except ValueError as e:
            return f"Error: {e}"

    def close(self):
        pass

    @staticmethod
    def from_dict(info):
        return MathCalcEnv(task=info, max_steps=info.get("max_steps", 3))

    @staticmethod
    def is_multithread_safe():
        return True


def _math_eval_names(calculate=None):
    names = {
        "abs": abs,
        "acos": math.acos,
        "asin": math.asin,
        "atan": math.atan,
        "binomial": math.comb,
        "ceil": math.ceil,
        "comb": math.comb,
        "cos": math.cos,
        "e": math.e,
        "exp": math.exp,
        "factorial": math.factorial,
        "floor": math.floor,
        "frac": lambda a, b: a / b,
        "ln": math.log,
        "log": math.log,
        "log10": math.log10,
        "pi": math.pi,
        "pow": pow,
        "sin": math.sin,
        "sqrt": math.sqrt,
        "tan": math.tan,
    }
    if calculate is not None:
        names["calculate"] = calculate
    return names


_SYMBOLIC_CALCULATOR_ERROR = "symbolic expression is not supported by calculate; use only numeric arithmetic"
_SYMBOLIC_FUNCTION_NAMES = {
    "derive",
    "differentiate",
    "diff",
    "expand",
    "factor",
    "integrate",
    "limit",
    "simplify",
    "solve",
    "subs",
    "sym",
}
_ALLOWED_CALCULATOR_NODES = (
    ast.Expression,
    ast.BinOp,
    ast.UnaryOp,
    ast.Call,
    ast.Name,
    ast.Load,
    ast.Constant,
    ast.Add,
    ast.Sub,
    ast.Mult,
    ast.Div,
    ast.Pow,
    ast.Mod,
    ast.USub,
    ast.UAdd,
    ast.Tuple,
)


def is_symbolic_calculator_error(message):
    return _SYMBOLIC_CALCULATOR_ERROR in str(message)


def validate_calculator_expression(expr, names):
    if len(expr) > 240:
        raise ValueError("expression too long")
    if "=" in expr:
        raise ValueError(_SYMBOLIC_CALCULATOR_ERROR)

    identifiers = set(re.findall(r"\b[A-Za-z_]\w*\b", expr))
    if identifiers & _SYMBOLIC_FUNCTION_NAMES:
        raise ValueError(_SYMBOLIC_CALCULATOR_ERROR)
    unknown_identifiers = identifiers - set(names)
    if unknown_identifiers:
        raise ValueError(_SYMBOLIC_CALCULATOR_ERROR)

    try:
        tree = ast.parse(expr, mode="eval")
    except SyntaxError as e:
        raise ValueError("invalid expression") from e
    for node in ast.walk(tree):
        if not isinstance(node, _ALLOWED_CALCULATOR_NODES):
            raise ValueError("invalid expression")
        if isinstance(node, ast.Constant) and not isinstance(node.value, (int, float)):
            raise ValueError("invalid expression")


def normalize_math_expression(expr):
    expr = str(expr).strip()
    expr = expr.replace("\\\\", "\\")
    expr = expr.replace("^", "**")
    expr = expr.replace("[", "(").replace("]", ")")
    expr = re.sub(r"\\frac\s*\{([^{}]+)\}\s*\{([^{}]+)\}", r"(\1)/(\2)", expr)
    expr = re.sub(r"\\sqrt\s*\{([^{}]+)\}", r"sqrt(\1)", expr)
    expr = expr.replace("\\pi", str(math.pi))
    expr = re.sub(r"(?<![A-Za-z_])C\s*\(", "comb(", expr)
    if not re.fullmatch(r"[0-9A-Za-z_+\-*/=()., '\"\t]+", expr):
        raise ValueError("invalid expression")
    return expr


def eval_answer_to_float(answer_str):
    if answer_str is None:
        return None
    text = str(answer_str).strip()
    mixed = re.fullmatch(r"(-?\d+)\s+\\frac\s*\{([^{}]+)\}\s*\{([^{}]+)\}", text)
    if mixed:
        whole = float(mixed.group(1))
        numerator = eval_answer_to_float(mixed.group(2))
        denominator = eval_answer_to_float(mixed.group(3))
        if numerator is not None and denominator not in (None, 0):
            sign = -1 if whole < 0 else 1
            return whole + sign * numerator / denominator

    numbers = re.findall(r'-?\d+\.?\d*', text)
    try:
        return float(text)
    except ValueError:
        pass
    try:
        return float(eval(normalize_math_expression(text), {"__builtins__": {}}, _math_eval_names()))
    except Exception:
        pass
    if numbers:
        try:
            return float(numbers[-1])
        except ValueError:
            return None
    return None


def score_numeric_answer(response, expected_answer):
    response_text = str(response)
    numbers = re.findall(r'-?\d+\.?\d*', response_text)
    predicted = eval_answer_to_float(response_text)
    if predicted is None:
        if not numbers:
            return 0.0
        predicted = float(numbers[-1])
    expected = eval_answer_to_float(expected_answer)
    if expected is None:
        return 0.0
    tolerance = max(1e-3, 1e-2 * abs(expected))
    if abs(predicted - expected) <= tolerance:
        return 1.0
    rel_err = abs(predicted - expected) / max(abs(expected), 1e-6)
    if rel_err < 0.1:
        return 0.5
    if rel_err < 0.5:
        return 0.2
    return 0.0


def _clamp(value, low, high):
    return max(low, min(high, value))


def score_math_trajectory(
    final_response,
    expected_answer,
    *,
    parsed_tool_call=False,
    synthetic_finish=False,
    finished=False,
    steps=0,
    max_steps=3,
    successful_calculates=0,
    calculator_errors=0,
    unknown_tools=0,
    symbolic_calculator_errors=0,
    parser_errors=0,
    malformed_tool_calls=0,
):
    correctness = score_numeric_answer(final_response, expected_answer)
    events = []

    answer_reward = 0.8 * correctness
    valid_finish = finished and not synthetic_finish and eval_answer_to_float(final_response) is not None
    protocol_bonus = 0.02 if parsed_tool_call else 0.0
    finish_bonus = 0.1 if valid_finish else 0.0
    tool_bonus = 0.08 if successful_calculates > 0 else 0.0
    penalty = 0.0

    if correctness >= 1.0:
        events.append("correct_answer")
    elif correctness > 0.0:
        events.append("partial_answer")
    if parsed_tool_call:
        events.append("parsed_tool_call")
    if valid_finish:
        events.append("valid_finish")
    elif finished:
        events.append("finish_used")
    if successful_calculates:
        events.append("successful_calculate")
    if calculator_errors:
        penalty += min(calculator_errors, 3) * 0.03
        events.append("calculator_error")
    if symbolic_calculator_errors:
        penalty += min(symbolic_calculator_errors, 3) * 0.02
        events.append("symbolic_calculator_error")
    if parser_errors:
        penalty += min(parser_errors, 3) * 0.02
        events.append("parser_error")
    if malformed_tool_calls:
        penalty += min(malformed_tool_calls, 3) * 0.02
        events.append("malformed_tool_call")
    if unknown_tools:
        penalty += min(unknown_tools, 3) * 0.03
        events.append("unknown_tool")
    if not finished and steps >= max_steps:
        penalty += 0.02
        events.append("no_finish")

    shaping = protocol_bonus + finish_bonus + tool_bonus - penalty
    total = _clamp(answer_reward + shaping, 0.0, 1.0)
    components = {
        "correctness": round(correctness, 6),
        "answer_reward": round(answer_reward, 6),
        "protocol_bonus": round(protocol_bonus, 6),
        "finish_bonus": round(finish_bonus, 6),
        "tool_bonus": round(tool_bonus, 6),
        "penalty": round(penalty, 6),
        "shaping": round(shaping, 6),
        "total": round(total, 6),
        "parsed_tool_call": bool(parsed_tool_call),
        "synthetic_finish": bool(synthetic_finish),
        "finished": bool(finished),
        "successful_calculates": int(successful_calculates),
        "calculator_errors": int(calculator_errors),
        "symbolic_calculator_errors": int(symbolic_calculator_errors),
        "parser_errors": int(parser_errors),
        "malformed_tool_calls": int(malformed_tool_calls),
        "unknown_tools": int(unknown_tools),
        "events": events,
    }
    return total, components


def generate_math_problems(n=100, seed=42, difficulty="mixed"):
    rng = random.Random(seed)
    problems = []

    def _simple(rng):
        ops = [("+", lambda a, b: a + b), ("-", lambda a, b: a - b), ("*", lambda a, b: a * b)]
        a, b = rng.randint(1, 100), rng.randint(1, 100)
        sym, fn = rng.choice(ops)
        return f"What is {a} {sym} {b}?", str(fn(a, b))

    def _multi_step(rng):
        templates = [
            lambda: _multi_step_chain(rng),
            lambda: _word_problem(rng),
            lambda: _percentage_problem(rng),
            lambda: _comparison_problem(rng),
        ]
        return rng.choice(templates)()

    def _multi_step_chain(rng):
        a, b, c = rng.randint(2, 50), rng.randint(2, 50), rng.randint(2, 20)
        op1, op2 = rng.choice([("+", "-"), ("*", "+"), ("+", "*"), ("-", "+"), ("*", "-")])
        expr = f"({a} {op1} {b}) {op2} {c}"
        answer = eval(expr)  # noqa: S307
        patterns = [
            f"First compute {a} {op1} {b}, then {op2} {c}. What is the result?",
            f"What is ({a} {op1} {b}) {op2} {c}?",
            f"Calculate: start with {a}, {_op_word(op1)} {b}, then {_op_word(op2)} {c}.",
        ]
        return rng.choice(patterns), str(answer)

    def _word_problem(rng):
        items = [("apples", "oranges"), ("books", "pens"), ("shirts", "pants"), ("tickets", "drinks")]
        item1, item2 = rng.choice(items)
        p1, p2 = rng.randint(2, 15), rng.randint(2, 15)
        q1, q2 = rng.randint(1, 10), rng.randint(1, 10)
        total = p1 * q1 + p2 * q2
        names = ["Alice", "Bob", "Charlie", "Diana", "Eve"]
        name = rng.choice(names)
        question = (
            f"{name} buys {q1} {item1} at ${p1} each and {q2} {item2} at ${p2} each. "
            f"How much does {name} spend in total?"
        )
        return question, str(total)

    def _percentage_problem(rng):
        base = rng.choice([50, 80, 100, 120, 150, 200, 250, 300, 400, 500])
        pct = rng.choice([10, 15, 20, 25, 30, 40, 50, 75])
        result = base * pct / 100
        patterns = [
            f"What is {pct}% of {base}?",
            f"A product costs ${base}. If there is a {pct}% discount, how much do you save?",
            f"Calculate {pct} percent of {base}.",
        ]
        answer = int(result) if result == int(result) else result
        return rng.choice(patterns), str(answer)

    def _comparison_problem(rng):
        a, b = rng.randint(5, 50), rng.randint(5, 50)
        c, d = rng.randint(1, 30), rng.randint(1, 30)
        val1, val2 = a * b, c * d
        question = (
            f"Store A sells {a} items at ${b} each. Store B sells {c} items at ${d} each. "
            f"How much more does the store with higher revenue earn?"
        )
        return question, str(abs(val1 - val2))

    def _op_word(op):
        return {"+" : "add", "-": "subtract", "*": "multiply by"}.get(op, op)

    for _ in range(n):
        if difficulty == "simple":
            q, a = _simple(rng)
        elif difficulty == "hard":
            q, a = _multi_step(rng)
        else:
            q, a = _multi_step(rng) if rng.random() > 0.8 else _simple(rng)
        problems.append({"question": q, "answer": str(a)})
    return problems

import asyncio
import json
import logging
import math
import re
import time

import torch

from rllm_train.hf_engine import HFAgentExecutionEngine
from rllm_train.math_env import MathCalcEnv

logger = logging.getLogger(__name__)


def make_rllm_rollout_func(
    agent_class,
    agent_args=None,
    env_class=None,
    env_args=None,
    max_steps=3,
    max_response_length=256,
    max_prompt_length=512,
    sampling_params=None,
    training_logger=None,
    trajectory_writer=None,
    perf_tracker=None,
    answer_map=None,
):
    if agent_args is None:
        agent_args = {}
    if env_args is None:
        env_args = {}
    if env_class is None:
        env_class = MathCalcEnv
    if sampling_params is None:
        sampling_params = {"temperature": 0.7, "top_p": 0.9}
    if answer_map is None:
        answer_map = {}

    _step_counter = [0]

    def rollout_func(prompts, trainer):
        _step_counter[0] += 1
        step = _step_counter[0]
        model = trainer.model
        tokenizer = trainer.processing_class
        device = trainer.accelerator.device

        num_gens = getattr(trainer.args, "num_generations", len(prompts))
        if training_logger:
            training_logger.log_rollout_start(step, len(prompts), num_gens)
        if perf_tracker:
            perf_tracker.start_rollout(step)

        model.eval()

        engine = HFAgentExecutionEngine(
            model=model,
            tokenizer=tokenizer,
            n_parallel_agents=len(prompts),
            max_steps=max_steps,
            max_response_length=max_response_length,
            max_prompt_length=max_prompt_length,
            agent_class=agent_class,
            agent_args=agent_args,
            env_class=env_class,
            env_args=env_args,
            sampling_params=sampling_params,
            on_trajectory_done=lambda idx, total, reward: (
                training_logger.log_trajectory_done(step, idx, total, reward)
                if training_logger else None
            ),
        )

        envs = []
        agents = []
        for prompt in prompts:
            task = _extract_task_from_prompt(prompt)
            if task["question"] in answer_map:
                task["answer"] = answer_map[task["question"]]
            task.update(env_args)
            env = env_class.from_dict(task)
            agent = agent_class(**agent_args)
            envs.append(env)
            agents.append(agent)

        engine.update_envs_and_agents(envs, agents)

        try:
            loop = asyncio.get_event_loop()
            if loop.is_running():
                import concurrent.futures
                with concurrent.futures.ThreadPoolExecutor() as pool:
                    results = pool.submit(
                        lambda: asyncio.run(engine.run_trajectories(mode="Token"))
                    ).result()
            else:
                results = loop.run_until_complete(engine.run_trajectories(mode="Token"))
        except RuntimeError:
            results = asyncio.run(engine.run_trajectories(mode="Token"))

        model.train()

        # Perf tracking: end rollout phase
        rollout_stats = None
        if perf_tracker:
            rollout_stats = perf_tracker.end_rollout(results)

        prompt_ids_list = []
        completion_ids_list = []
        env_mask_list = []

        for result in results:
            prompt_ids_list.append(result["prompt_tokens"].tolist())
            completion_ids_list.append(result["response_tokens"].tolist())
            env_mask_list.append(result["response_masks"].tolist())

        rewards = [r.get("trajectory_reward", 0.0) if isinstance(r, dict) else 0.0 for r in results]
        behavior_metrics = _compute_behavior_metrics(agents, results, max_steps, num_gens)
        if training_logger:
            training_logger.log_rollout_done(
                step,
                len(results),
                rewards,
                rollout_stats=rollout_stats,
                behavior_metrics=behavior_metrics,
            )

        # Compute logprobs with timing
        if training_logger:
            training_logger.log_logprob_start(step)
        if perf_tracker:
            perf_tracker.start_logprob_compute()

        logprobs_list = _compute_logprobs(
            model, tokenizer, prompt_ids_list, completion_ids_list, device
        )

        if perf_tracker:
            perf_tracker.end_logprob_compute()

        # Write trajectories to file (after logprobs are computed)
        if trajectory_writer:
            trajectory_writer.write_rollout(step, agents, envs, results, tokenizer, logprobs_list=logprobs_list)

        if training_logger:
            training_logger.log_training_update_start(step)

        return {
            "prompt_ids": prompt_ids_list,
            "completion_ids": completion_ids_list,
            "logprobs": logprobs_list,
            "env_mask": env_mask_list,
        }

    return rollout_func


def _compute_behavior_metrics(agents, results, max_steps, num_generations=8):
    total = len(results)
    if total == 0:
        return {}

    rewards = [float(r.get("trajectory_reward", 0.0)) for r in results if isinstance(r, dict)]
    reward_mean = sum(rewards) / len(rewards) if rewards else 0.0
    reward_variance = math.sqrt(sum((r - reward_mean) ** 2 for r in rewards) / len(rewards)) if rewards else 0.0

    # pass@1 and pass@K: group rewards by prompt (num_generations per prompt)
    pass1 = 0.0
    passK = 0.0
    if num_generations > 0 and total >= num_generations:
        num_prompts = total // num_generations
        pass1_count = 0
        passK_count = 0
        for p in range(num_prompts):
            group = rewards[p * num_generations:(p + 1) * num_generations]
            if any(r >= 1.0 for r in group):
                pass1_count += 1
            if all(r >= 1.0 for r in group):
                passK_count += 1
        pass1 = pass1_count / num_prompts
        passK = passK_count / num_prompts

    finish_count = 0
    finish_numeric_count = 0
    calculate_count = 0
    answer_count = 0
    truncation_count = 0
    parser_error_count = 0
    malformed_tool_count = 0
    synthetic_finish_count = 0
    calculator_error_count = 0
    symbolic_calculator_error_count = 0
    successful_calculate_count = 0
    no_finish_count = 0
    valid_finish_count = 0
    response_lengths = []
    agent_steps = []

    for agent, result in zip(agents, results):
        calls = _extract_tool_calls(agent)
        finish_calls = [c for c in calls if c.get("name") == "finish"]
        calculate_calls = [c for c in calls if c.get("name") == "calculate"]
        has_finish = bool(finish_calls)
        has_calculate = bool(calculate_calls)
        finish_values = [_finish_value(c) for c in finish_calls]
        has_numeric_finish = any(_is_numeric_answer(v) for v in finish_values)
        has_answer = any(_has_answer_text(v) for v in finish_values)

        if has_finish:
            finish_count += 1
        if has_numeric_finish:
            finish_numeric_count += 1
        if has_calculate:
            calculate_count += 1
        if has_answer:
            answer_count += 1

        step_infos = [getattr(step, "info", {}) for step in getattr(agent.trajectory, "steps", [])]
        reward_components = [info.get("reward_components") for info in step_infos if info.get("reward_components")]
        if any(info.get("parse_error_type") for info in step_infos):
            parser_error_count += 1
        if any(info.get("malformed_tool_call") for info in step_infos):
            malformed_tool_count += 1
        if any(info.get("synthetic_finish") for info in step_infos):
            synthetic_finish_count += 1
        if any((comp.get("calculator_errors") or 0) > 0 for comp in reward_components):
            calculator_error_count += 1
        if any((comp.get("symbolic_calculator_errors") or 0) > 0 for comp in reward_components):
            symbolic_calculator_error_count += 1
        if any((comp.get("successful_calculates") or 0) > 0 for comp in reward_components):
            successful_calculate_count += 1
        if any("no_finish" in (comp.get("events") or []) for comp in reward_components):
            no_finish_count += 1
        if any("valid_finish" in (comp.get("events") or []) for comp in reward_components):
            valid_finish_count += 1

        if isinstance(result, dict):
            steps = int(result.get("metrics", {}).get("steps", 0) or 0)
            reward = float(result.get("trajectory_reward", 0.0) or 0.0)
            if steps >= max_steps and reward == 0.0:
                truncation_count += 1
            agent_steps.append(steps)
            response_lengths.append(len(result.get("response_tokens", [])))

    return {
        "finish_rate": finish_count / total,
        "finish_format_rate": finish_numeric_count / finish_count if finish_count else 0.0,
        "tool_usage_rate": calculate_count / total,
        "truncation_rate": truncation_count / total,
        "answer_coverage": answer_count / total,
        "reward_variance": reward_variance,
        "parser_error_rate": parser_error_count / total,
        "malformed_tool_rate": malformed_tool_count / total,
        "synthetic_finish_rate": synthetic_finish_count / total,
        "calculator_error_rate": calculator_error_count / total,
        "symbolic_calculator_error_rate": symbolic_calculator_error_count / total,
        "successful_calculate_rate": successful_calculate_count / total,
        "no_finish_rate": no_finish_count / total,
        "valid_finish_rate": valid_finish_count / total,
        "avg_agent_steps": sum(agent_steps) / len(agent_steps) if agent_steps else 0.0,
        "completion_length_mean": sum(response_lengths) / len(response_lengths) if response_lengths else 0.0,
        "pass1": pass1,
        "passK": passK,
    }


def _extract_tool_calls(agent):
    calls = []
    for msg in getattr(agent, "chat_completions", []) or []:
        if not isinstance(msg, dict) or msg.get("role") != "assistant":
            continue
        content = msg.get("content") or ""
        for match in re.finditer(r"<tool_call>\s*(\{.*?\})\s*</tool_call>", content, flags=re.S):
            try:
                call = json.loads(match.group(1))
            except json.JSONDecodeError:
                continue
            name = str(call.get("name", "")).lower()
            args = call.get("arguments") or {}
            calls.append({"name": name, "arguments": args})
    return calls


def _finish_value(call):
    args = call.get("arguments") or {}
    if not isinstance(args, dict):
        return ""
    if "response" in args:
        return args["response"]
    if "answer" in args:
        return args["answer"]
    if len(args) == 1:
        return next(iter(args.values()))
    return ""


def _is_numeric_answer(value):
    text = str(value).strip()
    return bool(
        re.fullmatch(r"[-+]?\d+(?:\.\d+)?(?:\s*/\s*[-+]?\d+(?:\.\d+)?)?", text)
        or re.fullmatch(r"\\frac\{[-+]?\d+\}\{[-+]?\d+\}", text)
    )


def _has_answer_text(value):
    return bool(re.search(r"[-+]?\d+(?:\.\d+)?|\\frac\{[-+]?\d+\}\{[-+]?\d+\}", str(value)))


def _extract_task_from_prompt(prompt):
    if isinstance(prompt, list):
        for msg in prompt:
            if isinstance(msg, dict) and msg.get("role") == "user":
                return {"question": msg["content"]}
        return {"question": str(prompt)}
    return {"question": str(prompt)}


def _compute_logprobs(model, tokenizer, prompt_ids_list, completion_ids_list, device):
    logprobs_list = []
    for prompt_ids, completion_ids in zip(prompt_ids_list, completion_ids_list):
        if not completion_ids:
            logprobs_list.append([])
            continue
        input_ids = torch.tensor([prompt_ids + completion_ids], device=device)
        with torch.no_grad():
            outputs = model(input_ids)
            logits = outputs.logits
        prompt_len = len(prompt_ids)
        completion_logits = logits[0, prompt_len - 1:-1, :]
        completion_tokens = torch.tensor(completion_ids, device=device)
        log_probs = torch.log_softmax(completion_logits, dim=-1)
        token_logprobs = log_probs.gather(1, completion_tokens.unsqueeze(1)).squeeze(1)
        logprobs_list.append(token_logprobs.cpu().tolist())
    return logprobs_list

